





















































import _ from 'lodash';
import {
  Component,
  Prop,
  Vue,
  Watch,
} from 'vue-property-decorator';
import {
  State,
  Action,
} from 'vuex-class';
import { CARD } from '@/interface/card';
import CardPopover from '@/components/CardPopover.vue';
import CardChoose from '@/components/CardChoose.vue';
import { countAll, countUpgrade } from '@/utils/countUtil';
import { formatStr, effectStr } from '@/utils/stringUtil';
import { property } from '@/data/constans';

@Component({
  components: {
  CardPopover,
  CardChoose
  }
  })
export default class SimulatorAside extends Vue {
    @Prop() private title!: string
    @Prop() private Items!: Array < object >
        @State private currentData!: Array < any >
        @Action private saveCurrent!: (value: string) => void
        @Action private fullLevelXiu!: () => void
        @Action private fullLevelDu!: () => void
        @Action private fullLevelJu!: () => void
        @Action private emptyCurrentData!: () => void
    private $alert!: any
    private property!: object
    private $message!: any
    private $prompt!: any
    private data() {
      return {
        activeNames: ['1'],
        property,
        formatStr,
      };
    }
    private emptyData() {
      this.$alert('确定清空当前数据吗？', '提示', {
        confirmButtonText: '确定',
        callback: () => {
          this.emptyCurrentData();
        },
      });
    }
    private specalFormat(typeStr: string, value: number) {
      const newValue = _.floor(value, 0);
      return formatStr(typeStr, newValue);
    }
    private handleChange(val: any) {
      console.log(val);
    }
    private get resultComputed() {
      return countAll(this.currentData);
    }
    private get effect() {
      return effectStr(this.resultComputed);
    }
    private get upgradeConsume() {
      return countUpgrade(this.currentData);
    }
    private count() {
      this.$message({
        message: '正在努力开发中',
        type: 'warning',
      });
    }
    private save() {
      const filter = _.filter(this.currentData, (v: any) => !_.isEmpty(v));
      if (_.isEmpty(filter)) {
        this.$message.error('数据不能为空!');
        return;
      }
      this.$prompt('请输入保存名称', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
      }).then(({
        value }: any) => {
        // console.log('value:', value)
        this.saveCurrent(value);
        this.$message({
          message: '保存成功！',
          type: 'success',
        });
      }).catch(() => {
        this.$message({
          type: 'info',
          message: '取消保存',
        });
      });
    }
}
